const declToProduct = d => { const ref = modelMarket.products.find(p => p.cat.toLowerCase() === String(d.cat).toLowerCase()); const cat = ref ? ref.cat : d.cat; const same = modelMarket.products.filter(p => p.cat === cat); const avg = a => a.length ? a.reduce((s, x) => s + x, 0) / a.length : 0; const p0 = Math.round(avg(same.map(p => p.prixInitial)) || avg(modelMarket.products.map(p => p.prixInitial))); const days = Math.max(0, Math.ceil((new Date(d.date) - Date.now()) / 864e5)); const b = days <= 1 ? 0 : days <= 3 ? 1 : days <= 7 ? 2 : 3; const dec = Math.round(modelMarket.discountModel[cat]?.[b] ?? modelMarket.avgDiscount); const prob = Math.round(avg(same.map(p => p.prob)) || 60); return { id: d.id, declared: true, product: d.product, sub: d.cat, cat, etat: 'Frais', q: Number(d.q) || 0, days, store: d.partner || 'Socofrais', commune: d.city, region: 'Abidjan', prixInitial: p0, decote: dec, prixIA: Math.max(50, Math.round(p0 * (1 - dec / 100) / 10) * 10), prob, score: Math.min(99, Math.round(100 * (.45 * prob / 100 + .35 / (days + 1) + .2 * dec / 75))), photo: d.photo } };
function ProductModal({ p, inCart, add, close }) { return <div className="modal-overlay" onClick={close}><div className="modal-card card" onClick={e => e.stopPropagation()}><button className="modal-close" onClick={close}><X size={17} /></button><img className="modal-img" src={productImg(p)} alt={p.product} /><div className="modal-body"><div className="pcat-row"><span className="pcat">{p.cat}</span>{p.declared && <span className="pnew">Déclaration fournisseur validée</span>}</div><h3>{p.product}</h3><p className="modal-sub">{p.sub} · réf. {p.id}</p><div className="modal-facts"><div><span>ÉTAT</span><b>{p.etat}</b></div><div><span>QUANTITÉ DISPONIBLE</span><b>{fmt(p.q)} kg</b></div><div><span>EXPIRATION</span><b>{p.days} jour{p.days > 1 ? 's' : ''}</b></div><div><span>SCORE RECO IA</span><b>{p.score}/100</b></div><div><span>PRIX INITIAL</span><b>{fcfa(p.prixInitial)}/kg</b></div><div><span>DÉCOTE IA</span><b>-{p.decote}%</b></div></div><div className="price-row"><s>{fcfa(p.prixInitial)}</s><b>{fcfa(p.prixIA)}<small>/kg</small></b><span className="off">-{p.decote}%</span></div><small className="pqty">Lot complet : {fmt(p.q)} kg · {fcfa(p.prixIA * p.q)}</small><small className="pmodel"><Sparkles size={10} /> {p.declared ? `Prix IA estimé depuis l’historique de la catégorie ${p.cat}` : `Prédiction IA propre au produit · ${fmt(p.samples)} lots « ${p.sub} » analysés`}</small>{inCart ? <button className="add-cart in"><Check size={14} /> Dans le panier</button> : <button className="add-cart" onClick={add}><ShoppingCart size={14} /> Ajouter au panier</button>}</div></div></div> }
