const Card = ({ children, className = '' }) => <div className={'card ' + className}>{children}</div>;
function Kpi({ icon: Icon, label, value, unit, delta, color = 'blue' }) { const live = Icon === Boxes ? modelResults.dashboard.stock : Icon === PackageCheck ? modelResults.dashboard.routeRate : Icon === Clock3 ? modelResults.dashboard.matchHours : Icon === Leaf ? modelResults.dashboard.co2 : value; return <Card className="kpi" title="Calculé depuis waste2cash_dataset.csv"><div className={'kpi-icon ' + color}><Icon size={21} /></div><div className="kpi-label">{label}</div><div className="kpi-value">{String(live).replace('.', ',')}<small>{unit}</small></div><div className="kpi-delta"><ArrowUpRight size={14} />{delta}<span>· données modèle</span></div></Card> }
