document.addEventListener('click', e => { const b = e.target.closest('button'); if (!b) return; const t = b.textContent.trim(); if (t.includes('Consulter la méthodologie')) document.querySelector('.method-card')?.scrollIntoView({ behavior: 'smooth' }); else if (t.includes('Lancer le matching')) window.alert('Matching IA exécuté : les lots sont maintenant classés selon leur score de priorité calculé.'); else if (t.includes('Ajouter un partenaire')) window.alert('Formulaire partenaire ouvert en mode démonstration. Les six enseignes validées sont déjà actives.'); else if (t.includes('Découvrir notre vision')) window.alert('Objectif Waste2Cash : étendre le réseau de valorisation à l’échelle nationale.'); else if (t === 'Voir tout') window.alert('Toutes les opérations récentes sont déjà chargées pour cette démonstration.'); else if (b.classList.contains('icon-btn')) window.alert('Aucune nouvelle alerte critique.') });
